CREATE TABLE IF NOT EXISTS migrations (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, migration VARCHAR(190) NOT NULL UNIQUE, batch INT NOT NULL, executed_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS roles (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, name VARCHAR(50) NOT NULL UNIQUE, permissions_json JSON NULL) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS users (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, role_id BIGINT UNSIGNED NOT NULL, name VARCHAR(120) NOT NULL, email VARCHAR(190) NOT NULL UNIQUE, password_hash VARCHAR(255) NOT NULL, status ENUM('active','inactive') DEFAULT 'active', last_login_at DATETIME NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, CONSTRAINT fk_users_role FOREIGN KEY (role_id) REFERENCES roles(id)) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS login_attempts (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, ip_address VARCHAR(45) NOT NULL, email_hash CHAR(64) NOT NULL, attempts TINYINT UNSIGNED NOT NULL DEFAULT 0, locked_until DATETIME NULL, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, UNIQUE KEY uq_login_attempt(ip_address,email_hash), INDEX idx_login_locked(locked_until)) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS categories (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, parent_id BIGINT UNSIGNED NULL, name VARCHAR(120) NOT NULL, slug VARCHAR(150) NOT NULL UNIQUE, description TEXT NULL, image_path VARCHAR(255) NULL, sort_order INT DEFAULT 0, is_active TINYINT(1) DEFAULT 1, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, FOREIGN KEY (parent_id) REFERENCES categories(id) ON DELETE SET NULL) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS products (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, category_id BIGINT UNSIGNED NULL, name VARCHAR(190) NOT NULL, slug VARCHAR(220) NOT NULL UNIQUE, base_sku VARCHAR(100) NULL, short_description TEXT NULL, description LONGTEXT NULL, base_price DECIMAL(15,2) NOT NULL DEFAULT 0, base_cost DECIMAL(15,2) NOT NULL DEFAULT 0, unit VARCHAR(30) DEFAULT 'pcs', weight_grams INT UNSIGNED DEFAULT 0, min_order_qty INT UNSIGNED DEFAULT 1, is_featured TINYINT(1) DEFAULT 0, status ENUM('active','inactive') DEFAULT 'active', created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, FOREIGN KEY (category_id) REFERENCES categories(id) ON DELETE SET NULL, INDEX idx_products_status(status), INDEX idx_products_category(category_id)) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS product_variants (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, product_id BIGINT UNSIGNED NOT NULL, name VARCHAR(190) NOT NULL DEFAULT 'Default', sku VARCHAR(100) NOT NULL UNIQUE, barcode VARCHAR(100) NULL, price DECIMAL(15,2) NULL, cost DECIMAL(15,2) NULL, weight_grams INT UNSIGNED NULL, stock_qty INT NOT NULL DEFAULT 0, low_stock_threshold INT NOT NULL DEFAULT 5, is_default TINYINT(1) DEFAULT 0, is_active TINYINT(1) DEFAULT 1, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, FOREIGN KEY (product_id) REFERENCES products(id) ON DELETE CASCADE, INDEX idx_variants_product(product_id)) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS product_images (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, product_id BIGINT UNSIGNED NOT NULL, variant_id BIGINT UNSIGNED NULL, image_path VARCHAR(255) NOT NULL, alt_text VARCHAR(190) NULL, sort_order INT DEFAULT 0, is_primary TINYINT(1) DEFAULT 0, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (product_id) REFERENCES products(id) ON DELETE CASCADE, FOREIGN KEY (variant_id) REFERENCES product_variants(id) ON DELETE SET NULL) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS discounts (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, product_id BIGINT UNSIGNED NULL, variant_id BIGINT UNSIGNED NULL, name VARCHAR(150) NOT NULL, discount_type ENUM('percentage','fixed') NOT NULL, discount_value DECIMAL(15,2) NOT NULL, starts_at DATETIME NULL, ends_at DATETIME NULL, priority INT DEFAULT 0, is_active TINYINT(1) DEFAULT 1, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, FOREIGN KEY (product_id) REFERENCES products(id) ON DELETE CASCADE, FOREIGN KEY (variant_id) REFERENCES product_variants(id) ON DELETE CASCADE) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS stock_movements (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, variant_id BIGINT UNSIGNED NOT NULL, movement_type VARCHAR(40) NOT NULL, quantity_change INT NOT NULL, stock_before INT NOT NULL, stock_after INT NOT NULL, reference_type VARCHAR(40) NULL, reference_id BIGINT UNSIGNED NULL, notes TEXT NULL, user_id BIGINT UNSIGNED NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (variant_id) REFERENCES product_variants(id), FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE SET NULL, INDEX idx_stock_variant(variant_id)) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS stock_opnames (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, opname_number VARCHAR(50) NOT NULL UNIQUE, status ENUM('draft','counting','review','completed','cancelled') DEFAULT 'draft', started_at DATETIME NULL, completed_at DATETIME NULL, notes TEXT NULL, created_by BIGINT UNSIGNED NOT NULL, completed_by BIGINT UNSIGNED NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, FOREIGN KEY (created_by) REFERENCES users(id), FOREIGN KEY (completed_by) REFERENCES users(id) ON DELETE SET NULL) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS stock_opname_items (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, stock_opname_id BIGINT UNSIGNED NOT NULL, variant_id BIGINT UNSIGNED NOT NULL, system_qty INT NOT NULL, physical_qty INT NULL, difference_qty INT NULL, unit_cost_snapshot DECIMAL(15,2) DEFAULT 0, notes TEXT NULL, counted_by BIGINT UNSIGNED NULL, counted_at DATETIME NULL, UNIQUE KEY uq_opname_variant(stock_opname_id,variant_id), FOREIGN KEY (stock_opname_id) REFERENCES stock_opnames(id) ON DELETE CASCADE, FOREIGN KEY (variant_id) REFERENCES product_variants(id), FOREIGN KEY (counted_by) REFERENCES users(id) ON DELETE SET NULL) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS customers (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, name VARCHAR(120) NOT NULL, phone VARCHAR(30) NOT NULL, email VARCHAR(190) NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS orders (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, order_number VARCHAR(50) NOT NULL UNIQUE, customer_id BIGINT UNSIGNED NULL, customer_name VARCHAR(120) NOT NULL, customer_phone VARCHAR(30) NOT NULL, status ENUM('pending_whatsapp','confirmed','completed','cancelled') DEFAULT 'pending_whatsapp', subtotal DECIMAL(15,2) NOT NULL, discount_total DECIMAL(15,2) DEFAULT 0, shipping_cost DECIMAL(15,2) DEFAULT 0, grand_total DECIMAL(15,2) NOT NULL, shipping_method VARCHAR(100) NULL, shipping_address_json JSON NULL, customer_notes TEXT NULL, admin_notes TEXT NULL, whatsapp_opened_at DATETIME NULL, confirmed_at DATETIME NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, FOREIGN KEY (customer_id) REFERENCES customers(id) ON DELETE SET NULL, INDEX idx_orders_status(status)) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS order_items (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, order_id BIGINT UNSIGNED NOT NULL, product_id BIGINT UNSIGNED NULL, variant_id BIGINT UNSIGNED NULL, product_name VARCHAR(190) NOT NULL, variant_name VARCHAR(190) NULL, sku VARCHAR(100) NOT NULL, unit_price DECIMAL(15,2) NOT NULL, discount_amount DECIMAL(15,2) DEFAULT 0, quantity INT UNSIGNED NOT NULL, line_total DECIMAL(15,2) NOT NULL, FOREIGN KEY (order_id) REFERENCES orders(id) ON DELETE CASCADE, FOREIGN KEY (product_id) REFERENCES products(id) ON DELETE SET NULL, FOREIGN KEY (variant_id) REFERENCES product_variants(id) ON DELETE SET NULL) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS shipping_zones (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, name VARCHAR(120) NOT NULL, base_cost DECIMAL(15,2) NOT NULL DEFAULT 0, cost_per_kg DECIMAL(15,2) DEFAULT 0, free_shipping_minimum DECIMAL(15,2) NULL, is_active TINYINT(1) DEFAULT 1) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS themes (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, name VARCHAR(100) NOT NULL, slug VARCHAR(100) NOT NULL UNIQUE, config_json JSON NOT NULL, is_active TINYINT(1) DEFAULT 0, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS settings (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, setting_group VARCHAR(50) NOT NULL DEFAULT 'general', setting_key VARCHAR(100) NOT NULL UNIQUE, setting_value LONGTEXT NULL, value_type VARCHAR(20) DEFAULT 'string', is_public TINYINT(1) DEFAULT 0, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS audit_logs (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, user_id BIGINT UNSIGNED NULL, action VARCHAR(80) NOT NULL, entity_type VARCHAR(80) NULL, entity_id BIGINT UNSIGNED NULL, old_values_json JSON NULL, new_values_json JSON NULL, ip_address VARCHAR(45) NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE SET NULL) ENGINE=InnoDB;
INSERT IGNORE INTO migrations (migration,batch) VALUES ('202607150001_initial_schema',1);
